import type * as DMMF from '@prisma/dmmf'

const SCALAR_TYPE_MAP: Record<string, string> = {
  String: 'string',
  Boolean: 'boolean',
  Int: 'number',
  Float: 'number',
  BigInt: 'bigint',
  Decimal: 'string',
  DateTime: 'string',
  Json: 'unknown',
  Bytes: 'string',
}

/** Maps a DMMF scalar type name to its TypeScript equivalent. */
export function mapScalarType(type: string): string {
  return SCALAR_TYPE_MAP[type] ?? 'unknown'
}

/** Maps a DMMF field to its TypeScript type string, handling lists and optionality. */
export function fieldToTypeString(field: DMMF.Field, enumNames: Set<string>): string {
  let tsType: string

  switch (field.kind) {
    case 'scalar':
      tsType = mapScalarType(field.type)
      break
    case 'enum':
      tsType = enumNames.has(field.type) ? field.type : 'string'
      break
    case 'object':
      // Relations are excluded from the REST interface, but if referenced, use the model name
      tsType = field.type
      break
    default:
      tsType = 'unknown'
  }

  if (field.isList) {
    tsType = `${tsType}[]`
  }
  if (!field.isRequired) {
    tsType = `${tsType} | null`
  }

  return tsType
}

/** Renders a TypeScript enum declaration from a DMMF enum. */
export function renderEnum(enumDef: DMMF.DatamodelEnum): string {
  const members = enumDef.values.map((v) => `  ${v.name} = '${v.name}',`).join('\n')
  return `export enum ${enumDef.name} {\n${members}\n}`
}

/** Renders a TypeScript interface from a DMMF model, including only scalar and enum fields. */
export function renderModelInterface(model: DMMF.Model, enumNames: Set<string>): string {
  const scalarFields = model.fields.filter((f) => f.kind === 'scalar' || f.kind === 'enum')
  const lines = scalarFields.map((f) => `  ${f.name}: ${fieldToTypeString(f, enumNames)}`)
  return `export interface ${model.name} {\n${lines.join('\n')}\n}`
}

/**
 * Renders a "create" input type for a model.
 * Excludes auto-generated fields (id with default, createdAt, updatedAt).
 */
export function renderCreateInput(model: DMMF.Model, enumNames: Set<string>): string {
  const fields = model.fields.filter((f) => {
    if (f.kind === 'object') return false
    if (f.isGenerated) return false
    if (f.isUpdatedAt) return false
    if (f.isId && f.hasDefaultValue) return false
    return true
  })

  const lines = fields.map((f) => {
    const tsType = fieldToTypeString(f, enumNames)
    const optional = f.hasDefaultValue || !f.isRequired ? '?' : ''
    return `  ${f.name}${optional}: ${tsType}`
  })

  return `export interface ${model.name}CreateInput {\n${lines.join('\n')}\n}`
}

/**
 * Renders an "update" input type for a model.
 * All fields are optional since updates are partial.
 */
export function renderUpdateInput(model: DMMF.Model, enumNames: Set<string>): string {
  const fields = model.fields.filter((f) => {
    if (f.kind === 'object') return false
    if (f.isGenerated) return false
    if (f.isId) return false
    return true
  })

  const lines = fields.map((f) => {
    const baseType = fieldToTypeString(f, enumNames)
    return `  ${f.name}?: ${baseType}`
  })

  return `export interface ${model.name}UpdateInput {\n${lines.join('\n')}\n}`
}

/** Renders a "where unique" input type for a model, based on its unique/id fields. */
export function renderWhereUniqueInput(model: DMMF.Model, enumNames: Set<string>): string {
  const idFields = model.fields.filter((f) => f.isId)
  const uniqueFields = idFields.length > 0 ? idFields : model.fields.filter((f) => f.isUnique)

  const lines = uniqueFields.map((f) => `  ${f.name}: ${fieldToTypeString(f, enumNames)}`)

  return `export interface ${model.name}WhereUniqueInput {\n${lines.join('\n')}\n}`
}

/** Lowercases the first character of a string. */
export function lowerFirst(str: string): string {
  return str.charAt(0).toLowerCase() + str.slice(1)
}

/** Renders the CRUD methods for a single model as part of the REST client class. */
export function renderModelMethods(model: DMMF.Model): string {
  const name = model.name
  const resource = lowerFirst(name)

  return `  /** CRUD operations for ${name} */
  readonly ${resource} = {
    /** Retrieve all ${name} records, with optional query parameters. */
    findMany: (params?: Record<string, string>): Promise<${name}[]> => {
      return this.request<${name}[]>('GET', '/${resource}', undefined, params)
    },

    /** Retrieve a single ${name} by its unique fields. */
    findUnique: (where: ${name}WhereUniqueInput): Promise<${name} | null> => {
      const key = Object.values(where).join('/')
      return this.request<${name} | null>('GET', \`/${resource}/\${key}\`)
    },

    /** Create a new ${name} record. */
    create: (data: ${name}CreateInput): Promise<${name}> => {
      return this.request<${name}>('POST', '/${resource}', data)
    },

    /** Update an existing ${name} record. */
    update: (where: ${name}WhereUniqueInput, data: ${name}UpdateInput): Promise<${name}> => {
      const key = Object.values(where).join('/')
      return this.request<${name}>('PATCH', \`/${resource}/\${key}\`, data)
    },

    /** Delete a ${name} record. */
    delete: (where: ${name}WhereUniqueInput): Promise<${name}> => {
      const key = Object.values(where).join('/')
      return this.request<${name}>('DELETE', \`/${resource}/\${key}\`)
    },
  }`
}

/** Renders the file header with auto-generation notice and base client infrastructure. */
export function renderFileHeader(): string {
  return `// Auto-generated by @prisma/generator-rest-client — do not edit manually.

type HttpMethod = 'GET' | 'POST' | 'PATCH' | 'PUT' | 'DELETE'

export interface RestClientOptions {
  /** Base URL of the REST API (e.g. "https://api.example.com"). */
  baseUrl: string
  /** Optional headers to include with every request. */
  headers?: Record<string, string>
}`
}

/** Renders the RestClient class shell opening. */
export function renderClassOpen(): string {
  return `export class RestClient {
  readonly #baseUrl: string
  readonly #headers: Record<string, string>

  constructor(options: RestClientOptions) {
    this.#baseUrl = options.baseUrl.replace(/\\/+$/, '')
    this.#headers = {
      'Content-Type': 'application/json',
      ...options.headers,
    }
  }

  async request<T>(method: HttpMethod, path: string, body?: unknown, params?: Record<string, string>): Promise<T> {
    let url = \`\${this.#baseUrl}\${path}\`
    if (params) {
      const query = new URLSearchParams(params).toString()
      if (query) url += \`?\${query}\`
    }

    const response = await fetch(url, {
      method,
      headers: this.#headers,
      body: body !== undefined ? JSON.stringify(body) : undefined,
    })

    if (!response.ok) {
      throw new Error(\`REST client error: \${response.status} \${response.statusText}\`)
    }

    return response.json() as Promise<T>
  }`
}

/** Renders the class closing brace. */
export function renderClassClose(): string {
  return `}`
}

