import fs from 'node:fs/promises'
import path from 'node:path'

import type * as DMMF from '@prisma/dmmf'
import type { GeneratorOptions } from '@prisma/generator'

import {
  renderClassClose,
  renderClassOpen,
  renderCreateInput,
  renderEnum,
  renderFileHeader,
  renderModelInterface,
  renderModelMethods,
  renderUpdateInput,
  renderWhereUniqueInput,
} from './template'

/** Generates a typed REST API client file from the DMMF datamodel. */
export async function generate(options: GeneratorOptions): Promise<void> {
  const output = options.generator.output
  if (!output?.value) {
    throw new Error('No output directory specified for generator-rest-client')
  }
  const outputDir = output.value

  const { datamodel } = options.dmmf
  const content = generateRestClient(datamodel)

  await fs.mkdir(outputDir, { recursive: true })
  await fs.writeFile(path.join(outputDir, 'rest-client.ts'), content)
}

/** Produces the full rest-client.ts source from a DMMF datamodel. */
export function generateRestClient(datamodel: DMMF.Datamodel): string {
  const parts: string[] = []

  const enumNames = new Set(datamodel.enums.map((e) => e.name))

  parts.push(renderFileHeader())
  parts.push('')

  // Enums
  for (const enumDef of datamodel.enums) {
    parts.push(renderEnum(enumDef))
    parts.push('')
  }

  // Model interfaces + input types
  for (const model of datamodel.models) {
    parts.push(renderModelInterface(model, enumNames))
    parts.push('')
    parts.push(renderCreateInput(model, enumNames))
    parts.push('')
    parts.push(renderUpdateInput(model, enumNames))
    parts.push('')
    parts.push(renderWhereUniqueInput(model, enumNames))
    parts.push('')
  }

  // REST client class
  parts.push(renderClassOpen())
  parts.push('')
  const modelMethods = datamodel.models.map((model) => renderModelMethods(model))
  parts.push(modelMethods.join('\n\n'))
  parts.push(renderClassClose())
  parts.push('')

  return parts.join('\n')
}

